class Solution:
    def countBlackBlocks(self, m, n, coordinates):
        black = set(tuple(c) for c in coordinates)
        result = [0, 0, 0, 0, 0]
        for i in range(m - 1):
            for j in range(n - 1):
                c = 0
                for dx, dy in ((0, 0), (1, 0), (0, 1), (1, 1)):
                    if (i + dx, j + dy) in black:
                        c += 1
                result[c] += 1
        return result

