class Solution:
    def countBlackBlocks(self, m, n, coordinates):
        counts = {}
        for x, y in coordinates:
            for dx in (-1, 0):
                for dy in (-1, 0):
                    bx, by = x + dx, y + dy
                    if 0 <= bx <= m - 2 and 0 <= by <= n - 2:
                        counts[(bx, by)] = counts.get((bx, by), 0) + 1
        total_blocks = (m - 1) * (n - 1)
        result = [0, 0, 0, 0, 0]
        accounted = 0
        for v in counts.values():
            result[v] += 1
            accounted += 1
        result[0] = total_blocks - accounted
        return result

